import React, { useEffect, useState } from 'react';
import { Link, Navigate, useParams } from 'react-router-dom';
import toast from 'react-hot-toast';
import { nguoiDungAPI } from '../services/api';
import useAuthStore from '../store/authStore';
import './TrangCaNhanCongKhai.css';

const formatDate = value => (value ? new Date(value).toLocaleDateString('vi-VN') : 'Chưa cập nhật');

export default function TrangCaNhanCongKhai() {
  const { id } = useParams();
  const { user } = useAuthStore();
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const isCurrentUser = user && String(user.maNguoiDung) === String(id);

  useEffect(() => {
    let active = true;

    if (isCurrentUser) {
      setProfile(null);
      setLoading(false);
      return () => {
        active = false;
      };
    }

    setLoading(true);
    nguoiDungAPI.layTrangCaNhanCongKhai(id)
      .then(res => {
        if (active) {
          setProfile(res.data.data);
        }
      })
      .catch(() => {
        if (active) {
          setProfile(null);
          toast.error('Không tìm thấy trang cá nhân');
        }
      })
      .finally(() => {
        if (active) {
          setLoading(false);
        }
      });

    return () => {
      active = false;
    };
  }, [id, isCurrentUser]);

  if (isCurrentUser) {
    return <Navigate to="/ho-so" replace />;
  }

  if (loading) return <div className="spinner" />;

  if (!profile) {
    return (
      <div className="container page-wrapper">
        <div className="alert alert-danger">Không tìm thấy trang cá nhân này.</div>
      </div>
    );
  }

  const reviews = profile.danhGiaNhanDuoc || [];

  return (
    <div className="container page-wrapper">
      <div className="public-profile-hero card">
        <div className="card-body public-profile-hero-body">
          <img
            src={profile.avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(profile.hoTen || 'User')}&background=12355B&color=fff&size=160`}
            alt={profile.hoTen}
            className="avatar avatar-xl public-profile-avatar"
          />

          <div className="public-profile-main">
            <div className="public-profile-title-row">
              <h1>{profile.hoTen}</h1>
              {profile.xacThuc && <span className="badge badge-success">Đã xác thực CCCD</span>}
            </div>

            <div className="public-profile-meta">
              <span>Tham gia từ {formatDate(profile.ngayTao)}</span>
              <span>{profile.diemDanhGia ? `${profile.diemDanhGia.toFixed(1)} / 5 sao` : 'Chưa có đánh giá'}</span>
            </div>

            <div className="public-profile-actions">
              <span className="public-profile-owner-note">Đây là trang công khai của thành viên này.</span>
            </div>
          </div>
        </div>
      </div>

      <div className="grid-3 public-profile-stats">
        <div className="stat-card">
          <div className="stat-value">{profile.tongBaiDang || 0}</div>
          <div className="stat-label">Bài đăng đã tạo</div>
        </div>
        <div className="stat-card">
          <div className="stat-value">{profile.tongPhong || 0}</div>
          <div className="stat-label">Phòng đang quản lý</div>
        </div>
        <div className="stat-card">
          <div className="stat-value">{profile.diemDanhGia ? profile.diemDanhGia.toFixed(1) : '0.0'}</div>
          <div className="stat-label">Độ uy tín hiện tại</div>
        </div>
      </div>

      <div className="grid-2 public-profile-layout">
        <div className="card">
          <div className="card-header">Thông tin công khai</div>
          <div className="card-body">
            <div className="info-row">
              <span>Họ tên</span>
              <strong>{profile.hoTen}</strong>
            </div>
            <div className="info-row">
              <span>Tình trạng xác thực</span>
              <strong>{profile.xacThuc ? 'Đã xác thực CCCD' : 'Chưa xác thực'}</strong>
            </div>
            <div className="info-row">
              <span>Ngày tham gia</span>
              <strong>{formatDate(profile.ngayTao)}</strong>
            </div>
            <div className="info-row">
              <span>Đánh giá trung bình</span>
              <strong>{profile.diemDanhGia ? `${profile.diemDanhGia.toFixed(1)} / 5` : 'Chưa có'}</strong>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="card-header">Đánh giá nhận được</div>
          <div className="card-body">
            {reviews.length === 0 ? (
              <div className="review-empty">
                Thành viên này chưa nhận được đánh giá công khai nào.
              </div>
            ) : (
              <div className="review-list">
                {reviews.map(review => (
                  <div key={review.maDanhGia} className="review-item">
                    <div className="review-top">
                      <Link to={`/nguoi-dung/${review.maNguoiDanhGia}`} className="public-profile-reviewer">
                        <img
                          src={review.avatarNguoiDanhGia || `https://ui-avatars.com/api/?name=${encodeURIComponent(review.tenNguoiDanhGia || 'U')}&background=12355B&color=fff&size=40`}
                          alt={review.tenNguoiDanhGia}
                          className="avatar avatar-sm"
                        />
                        <strong>{review.tenNguoiDanhGia || 'Người dùng ẩn danh'}</strong>
                      </Link>
                      <span className="stars">{'★'.repeat(review.soSao || 0)}{'☆'.repeat(5 - (review.soSao || 0))}</span>
                    </div>
                    <div className="public-profile-review-content">
                      {review.moTa || 'Không có nhận xét chi tiết'}
                    </div>
                    <div className="review-date">{formatDate(review.ngayDanhGia)}</div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
